1	import { createServer } from "node:http";
2	import { readFileSync } from "node:fs";
3	import { resolve, dirname } from "node:path";
4	import { fileURLToPath } from "node:url";
5	import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
6	import { StreamableHTTPServerTransport } from "@modelcontextprotocol/sdk/server/streamableHttp.js";
7	import { z } from "zod";
8	import { getNasConfigs, nasPreview, nasExec, buildApprovalToken } from "./nas-client.js";
9	import {
10	  ALL_TOOL_DEFS,
11	  type McpToolDef,
12	  searchTools,
13	  formatToolForSearch,
14	  findToolByName,
15	  getGroup,
16	  listUntaggedTools,
17	} from "./nas-tools.js";
18	
19	// ─── Config ───────────────────────────────────────────────────────────────────
20	
21	const PORT = parseInt(process.env.MCP_PORT ?? "3001", 10);
22	const BEARER_TOKEN = process.env.MCP_BEARER_TOKEN ?? "";
23	
24	/**
25	 * Hard ceiling on any single tool invocation. Fires an MCP error rather than
26	 * letting the call hang until Claude Desktop's own 4-minute client timeout.
27	 * Must be comfortably less than Claude Desktop's 4-minute limit.
28	 */
29	const TOOL_DEADLINE_MS = 45_000;
30	
31	/**
32	 * Tools registered eagerly on every session in addition to tool_search /
33	 * invoke_tool / run_command. Two carefully chosen freebies for the most common
34	 * one-shot questions.
35	 */
36	const EAGER_TOOLS = ["check_disk_space", "restart_nas_api"] as const;
37	
38	const MCP_INSTRUCTIONS = `
39	This server intentionally exposes only 5 always-on tools per session:
40	tool_search, invoke_tool, run_command, check_disk_space, restart_nas_api.
41	
42	For any NAS diagnostic or admin task, call tool_search first unless the task is exactly disk-space checking, free-form read-only shell diagnosis, or restarting nas-api. Most NAS tools are hidden from tools/list by design and must be discovered with tool_search, then executed with invoke_tool({ name, target, args }).
43	
44	Use target "edgesynology1", "edgesynology2", or "both". Write tools require a preview first; execute only by calling again with confirmed: true inside args after approval.
45	
46	HTTP access requires Authorization: Bearer <MCP_BEARER_TOKEN>. Do not invent or expose token values.
47	`.trim();
48	
49	const __dirname = dirname(fileURLToPath(import.meta.url));
50	const configPath = resolve(__dirname, "../tools-config.json");
51	const toolsConfig = JSON.parse(readFileSync(configPath, "utf8")) as {
52	  enabled_read_tools: string[];
53	  enabled_write_tools: string[];
54	};
55	
56	const enabledRead = new Set<string>(toolsConfig.enabled_read_tools ?? []);
57	const enabledWrite = new Set<string>(toolsConfig.enabled_write_tools ?? []);
58	const allEnabled = new Set<string>([...enabledRead, ...enabledWrite]);
59	
60	// One-time startup warning for tools missing from TOOL_GROUPS — they still
61	// work via the "misc" fallback, but should be tagged eventually.
62	{
63	  const untagged = listUntaggedTools().filter((n) => allEnabled.has(n));
64	  if (untagged.length) {
65	    console.warn(
66	      `[nas-mcp] ${untagged.length} enabled tool(s) untagged in TOOL_GROUPS (assigned group="misc"): ${untagged.join(", ")}`,
67	    );
68	  }
69	}
70	
71	// ─── Tool deadline wrapper ────────────────────────────────────────────────────
72	
73	type ToolResult = { content: { type: "text"; text: string }[] };
74	
75	async function withToolDeadline(toolName: string, fn: () => Promise<ToolResult>): Promise<ToolResult> {
76	  let timer: ReturnType<typeof setTimeout>;
77	  const deadline = new Promise<ToolResult>((resolve) => {
78	    timer = setTimeout(() => {
79	      console.warn(`[nas-mcp] Tool "${toolName}" deadline reached after ${TOOL_DEADLINE_MS}ms`);
80	      resolve({
81	        content: [{
82	          type: "text" as const,
83	          text: `Tool "${toolName}" timed out after ${TOOL_DEADLINE_MS / 1000}s. The NAS may be under heavy load or unreachable. Try again in a moment, or target a single NAS instead of "both".`,
84	        }],
85	      });
86	    }, TOOL_DEADLINE_MS);
87	  });
88	  try {
89	    return await Promise.race([fn(), deadline]);
90	  } finally {
91	    clearTimeout(timer!);
92	  }
93	}
94	
95	async function executePredefinedToolOnNas(
96	  tool: McpToolDef,
97	  input: Record<string, unknown>,
98	  config: ReturnType<typeof getNasConfigs>[number],
99	): Promise<string> {
100	  let command: string;
101	  try {
102	    command = tool.buildCommand(input);
103	  } catch (err) {
104	    return `[${config.name}] Cannot build command: ${err instanceof Error ? err.message : String(err)}`;
105	  }
106	
107	  try {
108	    if (!tool.write) {
109	      const result = await nasExec(config, command, 1);
110	      const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
111	      return `[${config.name}]\n${output || "(no output)"}`;
112	    }
113	
114	    const preview = await nasPreview(config, command);
115	
116	    if (preview.blocked) {
117	      return `[${config.name}] Blocked by NAS API: ${preview.summary}`;
118	    }
119	
120	    if (preview.tier >= 2 && !input.confirmed) {
121	      return [
122	        `[${config.name}] This action requires your approval before it runs.`,
123	        ``,
124	        `Command that will execute:`,
125	        `\`\`\``,
126	        command,
127	        `\`\`\``,
128	        ``,
129	        `Call this tool again with confirmed: true to approve and execute.`,
130	        `If you do not want to proceed, do nothing — no changes have been made.`,
131	      ].join("\n");
132	    }
133	
134	    let approvalToken: string | undefined;
135	    if (preview.tier >= 2) {
136	      approvalToken = buildApprovalToken(config, command, preview.tier);
137	    }
138	
139	    const result = await nasExec(config, command, preview.tier, approvalToken);
140	    const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
141	    return `[${config.name}]\n${output || "(no output)"}`;
142	  } catch (err) {
143	    return `[${config.name}] Error: ${err instanceof Error ? err.message : String(err)}`;
144	  }
145	}
146	
147	/**
148	 * Runs a predefined tool against the requested target NAS(es), returning the
149	 * combined text result. Shared between eager registration and invoke_tool.
150	 */
151	async function runPredefinedTool(
152	  tool: McpToolDef,
153	  input: Record<string, unknown>,
154	): Promise<ToolResult> {
155	  const target = (input.target as string) ?? "both";
156	  const configs = getNasConfigs(target);
157	  if (configs.length === 0) {
158	    return {
159	      content: [{ type: "text" as const, text: `No NAS configured for target "${target}". Valid targets: edgesynology1, edgesynology2, both.` }],
160	    };
161	  }
162	  const results = await Promise.all(configs.map((config) => executePredefinedToolOnNas(tool, input, config)));
163	  return {
164	    content: [{ type: "text" as const, text: results.join("\n\n---\n\n") }],
165	  };
166	}
167	
168	/**
169	 * Registers a single predefined tool directly with the MCP server. Used only
170	 * for the small set of eagerly-loaded tools; everything else flows through
171	 * invoke_tool.
172	 */
173	function registerToolDef(server: McpServer, tool: McpToolDef): void {
174	  const params = tool.write
175	    ? {
176	        ...tool.params,
177	        confirmed: z
178	          .boolean()
179	          .optional()
180	          .default(false)
181	          .describe(
182	            "Set to true to execute after reviewing the command preview. Omit or set false to see what will happen first.",
183	          ),
184	      }
185	    : tool.params;
186	
187	  server.tool(tool.name, tool.description, params, async (input: Record<string, unknown>) => {
188	    return withToolDeadline(tool.name, () => runPredefinedTool(tool, input));
189	  });
190	}
191	
192	// ─── MCP server factory ───────────────────────────────────────────────────────
193	
194	function createMcpServer(): McpServer {
195	  const server = new McpServer(
196	    { name: "synology-nas", version: "1.0.0" },
197	    { instructions: MCP_INSTRUCTIONS },
198	  );
199	
200	  // ── Always-on tool 1: tool_search ─────────────────────────────────────────
201	  server.tool(
202	    "tool_search",
203	    "Search the NAS diagnostic + admin tool registry by keyword. Call this FIRST to find the right tool for the task, then call invoke_tool to execute. Returns tool names, descriptions, and parameter shapes as text. Try keywords like: snapshot, backup, drive, sync, disk, smart, btrfs, network, tailscale, memory, cpu, logs, package, restart, files, permission, acl, recover, recycle, security, audit, volume, space, task. Group names also work: system, performance, network, security, drive_sync, logs, storage, files, recovery, packages, backup, write_restart, write_storage, write_files, write_tasks, misc.",
204	    {
205	      query: z.string().describe("Keywords describing what you want to do, e.g. 'snapshot recovery', 'sharesync errors', 'restart drive package'."),
206	      limit: z.number().int().optional().default(8).describe("Max tools to return. Default 8, max 30."),
207	    },
208	    async ({ query, limit }: { query: string; limit?: number }) => {
209	      return withToolDeadline("tool_search", async () => {
210	        const matches = searchTools(query, allEnabled);
211	        if (matches.length === 0) {
212	          return {
213	            content: [{
214	              type: "text" as const,
215	              text: `No tools matched "${query}". Try broader keywords (e.g. snapshot, drive, disk, network, files, logs, restart) or a group name (system, performance, network, security, drive_sync, logs, storage, files, recovery, packages, backup, write_restart, write_storage, write_files, write_tasks).`,
216	            }],
217	          };
218	        }
219	        const cap = Math.max(1, Math.min(limit ?? 8, 30));
220	        const top = matches.slice(0, cap);
221	        const body = top.map(formatToolForSearch).join("\n\n");
222	        const more = matches.length > top.length
223	          ? `\n\n(${matches.length - top.length} additional match(es) not shown — refine the query or raise limit.)`
224	          : "";
225	        const header = `Found ${matches.length} tool(s) for "${query}". Showing top ${top.length}.\nExecute any of these with: invoke_tool({ name: "<tool>", target: "edgesynology1|edgesynology2|both", args: { ... } })\n\n`;
226	        return { content: [{ type: "text" as const, text: header + body + more }] };
227	      });
228	    },
229	  );
230	
231	  // ── Always-on tool 2: invoke_tool ─────────────────────────────────────────
232	  server.tool(
233	    "invoke_tool",
234	    "Execute a NAS tool discovered via tool_search. Pass the tool's exact name, the target NAS, and any tool-specific params in args. For write tools, include confirmed: true inside args to actually run (omit it first to see a preview). Returns the tool's output as text.",
235	    {
236	      name: z.string().describe("Exact tool name from tool_search output."),
237	      target: z
238	        .enum(["edgesynology1", "edgesynology2", "both"])
239	        .describe("Which NAS to run on."),
240	      args: z
241	        .record(z.unknown())
242	        .optional()
243	        .describe("Tool-specific parameters from the tool_search schema. For write tools, include confirmed: true to execute."),
244	    },
245	    async ({ name, target, args }: { name: string; target: string; args?: Record<string, unknown> }) => {
246	      return withToolDeadline(`invoke_tool:${name}`, async () => {
247	        const tool = findToolByName(name);
248	        if (!tool) {
249	          return {
250	            content: [{
251	              type: "text" as const,
252	              text: `Unknown tool: "${name}". Call tool_search first to discover available tools.`,
253	            }],
254	          };
255	        }
256	        const isEnabled = tool.write ? enabledWrite.has(name) : enabledRead.has(name);
257	        if (!isEnabled) {
258	          return {
259	            content: [{
260	              type: "text" as const,
261	              text: `Tool "${name}" exists but is disabled in tools-config.json (${tool.write ? "enabled_write_tools" : "enabled_read_tools"}). Group: ${getGroup(name)}.`,
262	            }],
263	          };
264	        }
265	        const input: Record<string, unknown> = { ...(args ?? {}), target };
266	        return runPredefinedTool(tool, input);
267	      });
268	    },
269	  );
270	
271	  // ── Always-on tool 3: run_command (free-form, tier-1-only) ────────────────
272	  if (enabledRead.has("run_command")) {
273	    server.tool(
274	      "run_command",
275	      "Run any read-only shell command on a Synology NAS for deep diagnosis. Write commands are automatically blocked by the NAS API validator before execution. A small set of commands is permanently hard-blocked regardless of how many you have run (e.g. recursive grep over @synologydrive/@SynologyDriveShareSync — grep a specific log file instead); a block is a stateless rule on the command pattern, never a rate limit or session limit, so retrying or reconnecting will not change it.",
276	      {
277	        target: z
278	          .enum(["edgesynology1", "edgesynology2", "both"])
279	          .describe("Which NAS to run on"),
280	        command: z.string().describe("The shell command to execute"),
281	      },
282	      async ({ target, command }: { target: string; command: string }) => {
283	        return withToolDeadline("run_command", async () => {
284	          const configs = getNasConfigs(target);
285	          if (configs.length === 0) {
286	            return {
287	              content: [{ type: "text" as const, text: `No NAS configured for target "${target}".` }],
288	            };
289	          }
290	          const results = await Promise.all(
291	            configs.map(async (config) => {
292	              try {
293	                const preview = await nasPreview(config, command);
294	                if (preview.blocked) {
295	                  return `[${config.name}] Blocked: ${preview.summary}`;
296	                }
297	                if (preview.tier >= 2) {
298	                  return `[${config.name}] This command requires write access and cannot be run via run_command. Add it to enabled_write_tools in tools-config.json, or use invoke_tool with a specific write tool.`;
299	                }
300	                const result = await nasExec(config, command, 1);
301	                const output = [result.stdout, result.stderr].filter(Boolean).join("\n");
302	                return `[${config.name}]\n${output || "(no output)"}`;
303	              } catch (err) {
304	                return `[${config.name}] Error: ${err instanceof Error ? err.message : String(err)}`;
305	              }
306	            }),
307	          );
308	          return {
309	            content: [{ type: "text" as const, text: results.join("\n\n---\n\n") }],
310	          };
311	        });
312	      },
313	    );
314	  }
315	
316	  // ── Eager freebies: check_disk_space + restart_nas_api ────────────────────
317	  // Common enough that paying tool_search round-trip for them isn't worth it.
318	  for (const eagerName of EAGER_TOOLS) {
319	    const tool = ALL_TOOL_DEFS.find((t) => t.name === eagerName);
320	    if (!tool) continue;
321	    const isEnabled = tool.write ? enabledWrite.has(tool.name) : enabledRead.has(tool.name);
322	    if (!isEnabled) continue;
323	    registerToolDef(server, tool);
324	  }
325	
326	  return server;
327	}
328	
329	
330	// ─── HTTP server ──────────────────────────────────────────────────────────────
331	
332	function isAuthorized(req: { headers: { authorization?: string } }): boolean {
333	  if (!BEARER_TOKEN) return true;
334	  return req.headers.authorization === `Bearer ${BEARER_TOKEN}`;
335	}
336	
337	const httpServer = createServer(async (req, res) => {
338	  res.setHeader("Access-Control-Allow-Origin", "*");
339	  res.setHeader("Access-Control-Allow-Methods", "GET, POST, DELETE, OPTIONS");
340	  res.setHeader("Access-Control-Allow-Headers", "Authorization, Content-Type, Mcp-Session-Id");
341	
342	  if (req.method === "OPTIONS") {
343	    res.writeHead(204);
344	    res.end();
345	    return;
346	  }
347	
348	  const url = new URL(req.url ?? "/", `http://localhost`);
349	
350	  // Health check — no auth required
351	  if (url.pathname === "/health" && req.method === "GET") {
352	    res.writeHead(200, { "Content-Type": "application/json" });
353	    res.end(
354	      JSON.stringify({
355	        status: "ok",
356	        service: "nas-mcp",
357	        read_tools: enabledRead.size,
358	        write_tools: enabledWrite.size,
359	        registry_tools: ALL_TOOL_DEFS.length,
360	        always_on: ["tool_search", "invoke_tool", "run_command", ...EAGER_TOOLS],
361	      }),
362	    );
363	    return;
364	  }
365	
366	  if (!isAuthorized(req as Parameters<typeof isAuthorized>[0])) {
367	    res.writeHead(401, { "Content-Type": "application/json" });
368	    res.end(JSON.stringify({ error: "Unauthorized" }));
369	    return;
370	  }
371	
372	  // MCP endpoint — fully stateless: each request gets its own transport+server.
373	  // No session Map means no stale-session failures after container restarts.
374	  // GET without session ID: the claude.ai proxy opens a standalone SSE notification
375	  // stream before sending any tool calls; stateless mode handles it cleanly.
376	  if (url.pathname === "/sse" || url.pathname === "/mcp") {
377	    const transport = new StreamableHTTPServerTransport({
378	      sessionIdGenerator: undefined,
379	      enableJsonResponse: true,
380	    });
381	    const mcpServer = createMcpServer();
382	    await mcpServer.connect(transport);
383	    transport.onerror = (err) => {
384	      console.warn("[nas-mcp] transport error:", err instanceof Error ? err.message : String(err));
385	    };
386	    await transport.handleRequest(req, res);
387	    return;
388	  }
389	
390	  res.writeHead(404, { "Content-Type": "application/json" });
391	  res.end(JSON.stringify({ error: "Not found" }));
392	});
393	
394	// Traefik (Coolify's proxy) keeps connections alive longer than Node's default
395	// 5s keepAliveTimeout. When Node closes the socket first, Traefik gets a reset
396	// and claude.ai shows "connection interrupted". Setting these above Traefik's
397	// idle timeout (90s) prevents that race.
398	httpServer.keepAliveTimeout = 120_000;
399	httpServer.headersTimeout = 125_000;
400	
401	httpServer.listen(PORT, "0.0.0.0", () => {
402	  console.log(`NAS MCP server listening on port ${PORT}`);
403	  console.log(`Registry: ${ALL_TOOL_DEFS.length} tools (${enabledRead.size} read + ${enabledWrite.size} write enabled)`);
404	  console.log(`Always-on: tool_search, invoke_tool, run_command, ${EAGER_TOOLS.join(", ")}`);
405	});
