3534	function describeZodParam(schema: z.ZodTypeAny): string {
3535	  let inner: z.ZodTypeAny = schema;
3536	  let optional = false;
3537	  let defaultVal: unknown;
3538	  // Unwrap ZodOptional / ZodDefault chains
3539	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
3540	  while ((inner as any)?._def?.typeName === "ZodOptional" || (inner as any)?._def?.typeName === "ZodDefault") {
3541	    // eslint-disable-next-line @typescript-eslint/no-explicit-any
3542	    const d: any = (inner as any)._def;
3543	    if (d.typeName === "ZodOptional") optional = true;
3544	    if (d.typeName === "ZodDefault") {
3545	      try { defaultVal = d.defaultValue?.(); } catch { /* ignore */ }
3546	    }
3547	    inner = d.innerType;
3548	  }
3549	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
3550	  const tn: string | undefined = (inner as any)?._def?.typeName;
3551	  let type = "unknown";
3552	  if (tn === "ZodString") type = "string";
3553	  else if (tn === "ZodNumber") type = "number";
3554	  else if (tn === "ZodBoolean") type = "boolean";
3555	  // eslint-disable-next-line @typescript-eslint/no-explicit-any
3556	  else if (tn === "ZodEnum") type = ((inner as any)._def.values as string[]).map((v) => JSON.stringify(v)).join(" | ");
3557	  else if (tn === "ZodArray") type = "array";
3558	  else if (tn === "ZodObject" || tn === "ZodRecord") type = "object";
3559	
3560	  const flags: string[] = [];
3561	  if (optional) flags.push("optional");
3562	  if (defaultVal !== undefined) flags.push(`default=${JSON.stringify(defaultVal)}`);
3563	  const flagStr = flags.length ? ` (${flags.join(", ")})` : "";
3564	  const desc = schema.description ? `  // ${schema.description}` : "";
3565	  return `${type}${flagStr}${desc}`;
3566	}
3567	
3568	export function formatToolForSearch(tool: McpToolDef): string {
3569	  const lines: string[] = [];
3570	  lines.push(`TOOL: ${tool.name}`);
3571	  lines.push(`GROUP: ${getGroup(tool.name)}`);
3572	  lines.push(`TYPE: ${tool.write ? "write (requires confirmed: true to execute)" : "read"}`);
3573	  lines.push(`DESCRIPTION: ${tool.description}`);
3574	  const paramKeys = Object.keys(tool.params);
3575	  if (paramKeys.length === 0) {
3576	    lines.push(`PARAMS: (none)`);
3577	  } else {
3578	    lines.push(`PARAMS:`);
3579	    for (const key of paramKeys) {
3580	      lines.push(`  ${key}: ${describeZodParam(tool.params[key])}`);
3581	    }
3582	    if (tool.write) {
3583	      lines.push(`  confirmed: boolean (optional, default=false — omit to preview, set true to execute)`);
3584	    }
3585	  }
3586	  return lines.join("\n");
3587	}
3588	
3589	export function findToolByName(name: string): McpToolDef | undefined {
3590	  return ALL_TOOL_DEFS.find((t) => t.name === name);
3591	}
3592	
3593	// ─── JSON-schema view (for the issue-agent Stage 2 tool catalog) ──────────────
3594	// nas-mcp uses the Zod `params` directly with server.tool(); the web issue agent
3595	// needs a provider-native JSON-schema input. This converts the small param
3596	// vocabulary used here (string/number/boolean/enum, optional/default) without a
3597	// json-schema dependency.
3598	
3599	export interface ToolJsonSchema {
3600	  type: "object";
3601	  properties: Record<string, Record<string, unknown>>;
3602	  required?: string[];
3603	}
3604	
3605	function zodFieldToJson(schema: z.ZodTypeAny): { json: Record<string, unknown>; required: boolean } {
3606	  const description = (schema as { description?: string }).description;
3607	  let required = true;
3608	  let s: z.ZodTypeAny = schema;
3609	  // Unwrap optional/default/nullable wrappers.
3610	  for (let i = 0; i < 6; i += 1) {
3611	    const tn = (s as { _def?: { typeName?: string } })._def?.typeName;
3612	    if (tn === "ZodOptional" || tn === "ZodDefault" || tn === "ZodNullable") {
3613	      required = false;
3614	      s = (s as unknown as { _def: { innerType: z.ZodTypeAny } })._def.innerType;
