40	async function requestJson<T>(
41	  config: NasConfig,
42	  path: string,
43	  body: Record<string, unknown>,
44	  timeoutMs: number,
45	  label: string,
46	): Promise<T> {
47	  const url = new URL(path, config.url);
48	  const payload = JSON.stringify(body);
49	  const requestImpl = url.protocol === "https:" ? httpsRequest : httpRequest;
50	
51	  return new Promise<T>((resolve, reject) => {
52	    const req = requestImpl(
53	      url,
54	      {
55	        method: "POST",
56	        agent: false,
57	        headers: {
58	          "Content-Type": "application/json",
59	          "Content-Length": Buffer.byteLength(payload),
60	          Authorization: `Bearer ${config.apiSecret}`,
61	          Connection: "close",
62	        },
63	      },
64	      (res) => {
65	        res.setEncoding("utf8");
66	
67	        let raw = "";
68	        res.on("data", (chunk: string) => {
69	          raw += chunk;
70	          if (raw.length > MAX_RESPONSE_BYTES) {
71	            res.destroy(new Error(`${label} failed (${config.name}): response exceeded ${MAX_RESPONSE_BYTES} bytes`));
72	          }
73	        });
74	        res.on("end", () => {
75	          const status = res.statusCode ?? 500;
76	          if (status < 200 || status >= 300) {
77	            reject(new Error(`${label} failed (${config.name}): HTTP ${status} — ${raw.trim()}`));
78	            return;
79	          }
80	          try {
81	            resolve(JSON.parse(raw) as T);
82	          } catch (err) {
83	            reject(new Error(`${label} failed (${config.name}): invalid JSON response: ${err instanceof Error ? err.message : String(err)}`));
84	          }
85	        });
86	        res.on("error", reject);
87	      },
88	    );
89	
90	    req.setTimeout(timeoutMs, () => {
91	      req.destroy(new Error("__NAS_TIMEOUT__"));
92	    });
93	    req.on("error", reject);
94	    req.write(payload);
95	    req.end();
96	  }).catch((err) => {
97	    throw normalizeRequestError(err, `${label} (${config.name})`, timeoutMs);
98	  });
99	}
