## 6. How invoke_tool & tool_search Work

**tool_search dispatch** (lines 201–229, `index.ts`):
```typescript
server.tool(
  "tool_search",
  "Search the NAS diagnostic + admin tool registry by keyword...",
  {
    query: z.string().describe("Keywords describing what you want to do..."),
    limit: z.number().int().optional().default(8).describe("Max tools to return..."),
  },
  async ({ query, limit }: { query: string; limit?: number }) => {
    const matches = searchTools(query, allEnabled);  // Call search function
    // ... format and return top N tools as text
  },
);
```

**searchTools implementation** (`nas-tools.ts:3475–3532`):
```typescript
export function searchTools(query: string, enabled: Set<string>): McpToolDef[] {
  const lower = query.toLowerCase().trim();
  if (!lower) return [];
  const words = lower.split(/\s+/).filter(Boolean);

  // For each query word, build set of matching tools:
  // - Direct group name (e.g. "files"): only tools in that group
  // - KEYWORD_TO_GROUPS alias (e.g. "snapshot"): mapped groups + name/description
  // - No mapping: name/description substring match
  const perWord: Set<string>[] = words.map((word) => {
    const matching = new Set<string>();
    if (KNOWN_GROUPS.has(word)) {
      for (const tool of ALL_TOOL_DEFS) {
        if (enabled.has(tool.name) && getGroup(tool.name) === word) matching.add(tool.name);
      }
    } else {
      const mappedGroups = new Set<string>(KEYWORD_TO_GROUPS[word] ?? []);
      for (const tool of ALL_TOOL_DEFS) {
        if (!enabled.has(tool.name)) continue;
        if (
          mappedGroups.has(getGroup(tool.name)) ||
          tool.name.toLowerCase().includes(word) ||
          tool.description.toLowerCase().includes(word)
        ) {
          matching.add(tool.name);
        }
      }
    }
    return matching;
  });

  // AND semantics: tool must match every query word
  let candidates = perWord[0];
  for (let i = 1; i < perWord.length; i++) {
    const next = new Set<string>();
    for (const name of candidates) {
      if (perWord[i].has(name)) next.add(name);
    }
    candidates = next;
  }

  // Score: name match +3, description match +1 per word
  const toolMap = new Map<string, McpToolDef>(ALL_TOOL_DEFS.map((t) => [t.name, t]));
  const scored: { tool: McpToolDef; score: number }[] = [];
  for (const name of candidates) {
    const tool = toolMap.get(name)!;
    let score = 0;
    const nameLower = tool.name.toLowerCase();
    const descLower = tool.description.toLowerCase();
    for (const word of words) {
      if (nameLower.includes(word)) score += 3;
      if (descLower.includes(word)) score += 1;
    }
    scored.push({ tool, score });
  }
  scored.sort((a, b) => b.score - a.score || a.tool.name.localeCompare(b.tool.name));
  return scored.map((s) => s.tool);
}
```

**formatToolForSearch** (`nas-tools.ts:3568–3587`):
```typescript
export function formatToolForSearch(tool: McpToolDef): string {
  const lines: string[] = [];
  lines.push(`TOOL: ${tool.name}`);
  lines.push(`GROUP: ${getGroup(tool.name)}`);
  lines.push(`TYPE: ${tool.write ? "write (requires confirmed: true to execute)" : "read"}`);
  lines.push(`DESCRIPTION: ${tool.description}`);
  const paramKeys = Object.keys(tool.params);
  if (paramKeys.length === 0) {
    lines.push(`PARAMS: (none)`);
  } else {
    lines.push(`PARAMS:`);
    for (const key of paramKeys) {
      lines.push(`  ${key}: ${describeZodParam(tool.params[key])}`);
    }
    if (tool.write) {
      lines.push(`  confirmed: boolean (optional, default=false — omit to preview, set true to execute)`);
    }
  }
  return lines.join("\n");
}
```

**invoke_tool dispatch** (lines 232–269, `index.ts`):
```typescript
server.tool(
  "invoke_tool",
  "Execute a NAS tool discovered via tool_search...",
  {
    name: z.string().describe("Exact tool name from tool_search output."),
    target: z.enum(["edgesynology1", "edgesynology2", "both"]).describe("Which NAS to run on."),
    args: z.record(z.unknown()).optional().describe("Tool-specific parameters..."),
  },
  async ({ name, target, args }: { name: string; target: string; args?: Record<string, unknown> }) => {
    const tool = findToolByName(name);  // Find from ALL_TOOL_DEFS by name
    if (!tool) {
      return { content: [{ type: "text" as const, text: `Unknown tool: "${name}"...` }] };
    }
    const isEnabled = tool.write ? enabledWrite.has(name) : enabledRead.has(name);
    if (!isEnabled) {
      return { content: [{ type: "text" as const, text: `Tool "${name}" exists but is disabled in tools-config.json...` }] };
    }
    const input: Record<string, unknown> = { ...(args ?? {}), target };
    return runPredefinedTool(tool, input);  // Execute via common handler
  },
);
```

**runPredefinedTool** (lines 151–166, `index.ts`): Executes the tool against all targeted NAS units in parallel:
```typescript
async function runPredefinedTool(
  tool: McpToolDef,
  input: Record<string, unknown>,
): Promise<ToolResult> {
  const target = (input.target as string) ?? "both";
  const configs = getNasConfigs(target);
  if (configs.length === 0) {
    return {
      content: [{ type: "text" as const, text: `No NAS configured for target "${target}"...` }],
    };
  }
  const results = await Promise.all(configs.map((config) => executePredefinedToolOnNas(tool, input, config)));
  return {
    content: [{ type: "text" as const, text: results.join("\n\n---\n\n") }],
  };
}
```

